class Solution {
    public long minSumSquareDiff(int[] nums1, int[] nums2, int k1, int k2) {
        int n = nums1.length;
        long[] diff = new long[n];
        for (int i = 0; i < n; i++) {
            diff[i] = (long) (nums1[i] - nums2[i]) * (nums1[i] - nums2[i]);
        }
        Arrays.sort(diff);
        long sum = 0;
        for (int i = 0; i < n; i++) {
            sum += diff[i];
        }
        long left = 0, right = sum;
        while (left < right) {
            long mid = left + (right - left) / 2;
            if (check(mid, diff, k1, k2)) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    private boolean check(long mid, long[] diff, int k1, int k2) {
        long k1Used = 0, k2Used = 0;
        for (long d : diff) {
            if (d > mid) {
                long diffToCover = d - mid;
                if (k1Used + k2Used >= diffToCover) {
                    return true;
                }
                if (k1 > k1Used) {
                    k1Used += (int) Math.min(k1 - k1Used, diffToCover);
                } else if (k2 > k2Used) {
                    k2Used += (int) Math.min(k2 - k2Used, diffToCover);
                } else {
                    return false;
                }
            }
        }
        return true;
    }
}
